package com.oneil.wellness.walkplanner.activity;import jakarta.persistence.*;import java.time.Instant;import java.util.UUID;@Entity @Table(name="opportunity_outcome")public class OpportunityOutcome{@Id private UUID id;@Column(name="recommendation_history_id",nullable=false)private UUID recommendationHistoryId;@Enumerated(EnumType.STRING)@Column(name="outcome_status",nullable=false)private ActivityStatus status;@Enumerated(EnumType.STRING)@Column(nullable=false)private ActivitySource source;@Column(name="recorded_at",nullable=false)private Instant recordedAt;protected OpportunityOutcome(){}public OpportunityOutcome(UUID recommendation,ActivityStatus value,ActivitySource origin){id=UUID.randomUUID();recommendationHistoryId=recommendation;status=value;source=origin;recordedAt=Instant.now();}public UUID getId(){return id;}public UUID getRecommendationHistoryId(){return recommendationHistoryId;}public ActivityStatus getStatus(){return status;}public ActivitySource getSource(){return source;}public Instant getRecordedAt(){return recordedAt;}}
